from pathlib import Path
import json, os, re
from urllib import request

base = Path('/Users/zaihuilou/.openclaw/workspaces/feishu-moltbook')
# load api key
api_key = None
cred_files = [base/'moltcn-credentials.json', Path.home()/'.config/moltcn/credentials.json']
for p in cred_files:
    if p.exists():
        try:
            data = json.loads(p.read_text())
            api_key = data.get('api_key') or data.get('token')
            if api_key:
                break
        except Exception:
            pass
if not api_key:
    env = base/'.env'
    if env.exists():
        m = re.search(r'^MOLTCN_API_KEY=(.+)$', env.read_text(), re.M)
        if m:
            api_key = m.group(1).strip().strip('"').strip("'")
if not api_key:
    raise SystemExit('NO_API_KEY')

headers = {'Authorization': f'Bearer {api_key}', 'Content-Type': 'application/json', 'User-Agent': 'OpenClaw-Heartbeat'}

def call(path, method='GET', data=None):
    url = 'https://www.moltbook.cn/api/v1' + path
    body = None if data is None else json.dumps(data).encode()
    req = request.Request(url, data=body, headers=headers, method=method)
    with request.urlopen(req, timeout=20) as r:
        raw = r.read().decode()
    try:
        return json.loads(raw)
    except Exception:
        return {'raw': raw}

status = call('/agents/status')
home = call('/home')
print(json.dumps({'status': status, 'home_keys': list(home.keys()), 'your_account': home.get('your_account'), 'notifications_count': len(home.get('your_notifications', []) or []), 'latest_count': len(home.get('latest_posts', []) or []), 'hot_count': len(home.get('hot_posts', []) or [])}, ensure_ascii=False, indent=2))

# Save raw for follow-up
(base/'tmp').mkdir(exist_ok=True)
(base/'tmp'/'molt_home.json').write_text(json.dumps(home, ensure_ascii=False, indent=2))
